import React, { useState, useEffect } from 'react';
import { useHistory } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import '../styles/LoginModal.css';

const LoginModal = ({ isOpen, onClose, onRegisterClick }) => {
    const { t } = useTranslation();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [rememberMe, setRememberMe] = useState(false);
    const [isVisible, setIsVisible] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [formError, setFormError] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    
    // Form state management
    const [currentForm, setCurrentForm] = useState('login'); // 'login', 'register', 'forgot'
    
    // Registration states
    const [registerData, setRegisterData] = useState({
        firstName: '',
        lastName: '',
        email: '',
        password: '',
        confirmPassword: '',
        role: 'student'
    });
    const [registerLoading, setRegisterLoading] = useState(false);
    const [registerMessage, setRegisterMessage] = useState('');
    const [registerError, setRegisterError] = useState('');
    const [showRegisterPassword, setShowRegisterPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);

    // Forgot password states
    const [forgotEmail, setForgotEmail] = useState('');
    const [forgotLoading, setForgotLoading] = useState(false);
    const [forgotMessage, setForgotMessage] = useState('');
    const [forgotError, setForgotError] = useState('');

    const history = useHistory();
    const API_BASE_URL = process.env.REACT_APP_API_URL;

    // Modal visibility and body scroll management
    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
            requestAnimationFrame(() => {
                setIsVisible(true);
            });
        } else {
            setIsVisible(false);
            document.body.style.overflow = 'auto';
        }
        
        return () => {
            document.body.style.overflow = 'auto';
        };
    }, [isOpen]);

    // Close modal on escape key
    useEffect(() => {
        const handleEsc = (event) => {
            if (event.keyCode === 27) onClose();
        };
        window.addEventListener('keydown', handleEsc);
        
        return () => {
            window.removeEventListener('keydown', handleEsc);
        };
    }, [onClose]);

    // Initialize animated background elements
    useEffect(() => {
        if (isVisible) {
            const createAnimatedElements = () => {
                const overlay = document.querySelector('.login-modal-overlay');
                if (!overlay) return;
                
                // Clear existing elements
                const existingElements = overlay.querySelectorAll('.animated-element');
                existingElements.forEach(el => el.remove());
                
                // Create floating shapes
                const shapes = ['circle', 'hexagon', 'triangle'];
                const count = window.innerWidth > 768 ? 6 : 4;
                
                for (let i = 0; i < count; i++) {
                    const element = document.createElement('div');
                    element.className = `animated-element ${shapes[i % shapes.length]}`;
                    
                    const size = Math.random() * 80 + 40;
                    const posX = Math.random() * 100;
                    const posY = Math.random() * 100;
                    const duration = Math.random() * 20 + 15;
                    const delay = Math.random() * 5;
                    
                    element.style.width = `${size}px`;
                    element.style.height = `${size}px`;
                    element.style.left = `${posX}%`;
                    element.style.top = `${posY}%`;
                    element.style.animationDuration = `${duration}s`;
                    element.style.animationDelay = `${delay}s`;
                    
                    overlay.appendChild(element);
                }
            };
            
            createAnimatedElements();
            window.addEventListener('resize', createAnimatedElements);
            
            return () => {
                window.removeEventListener('resize', createAnimatedElements);
            };
        }
    }, [isVisible]);

    // Login handler
    const handleLogin = async (e) => {
        e.preventDefault();
        setFormError('');
        setIsLoading(true);
        
        try {
            const response = await fetch(`${API_BASE_URL}/api/auth/login`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    email,
                    password
                })
            });

            const contentType = response.headers.get('content-type');
            if (!contentType || !contentType.includes('application/json')) {
                throw new Error('Server returned non-JSON response. Check if the API endpoint exists.');
            }

            const data = await response.json();
            
            if (!response.ok) {
                throw new Error(data.message || t('login.errors.loginFailed'));
            }
            
            // Store authentication data
            localStorage.setItem('authToken', data.token);
            localStorage.setItem('userRole', data.role || data.user?.role);
            localStorage.setItem('userEmail', data.user?.email || email);
            localStorage.setItem('userName', `${data.user?.firstName || ''} ${data.user?.lastName || ''}`.trim());
            localStorage.setItem('userId', data.user?.id);
            
            // Close modal and redirect
            onClose();
            history.push('/dashboard');
            
        } catch (error) {
            console.error('Login error:', error);
            
            let errorMessage = t('login.errors.invalidCredentials');
            
            if (error.message.includes('non-JSON response')) {
                errorMessage = 'Server error. Please check if the backend is running properly.';
            } else if (error.message.includes('Failed to fetch')) {
                errorMessage = 'Cannot connect to server. Please check your internet connection.';
            } else if (error.message) {
                errorMessage = error.message;
            }
            
            setFormError(errorMessage);
        } finally {
            setIsLoading(false);
        }
    };

    // Registration handler
    const handleRegister = async (e) => {
        e.preventDefault();
        setRegisterError('');
        setRegisterMessage('');
        setRegisterLoading(true);

        // Validate password confirmation
        if (registerData.password !== registerData.confirmPassword) {
            setRegisterError(t('login.register.passwordMismatch'));
            setRegisterLoading(false);
            return;
        }

        // Validate password strength
        if (registerData.password.length < 6) {
            setRegisterError(t('login.register.passwordTooShort'));
            setRegisterLoading(false);
            return;
        }

        try {
            const response = await fetch(`${API_BASE_URL}/api/auth/register`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    firstName: registerData.firstName,
                    lastName: registerData.lastName,
                    email: registerData.email,
                    password: registerData.password,
                    role: registerData.role
                })
            });

            const data = await response.json();

            if (!response.ok) {
                throw new Error(data.message || t('login.register.registrationFailed'));
            }

            setRegisterMessage(t('login.register.successMessage'));
            
            // Reset form and switch back to login after success
            setTimeout(() => {
                setRegisterData({
                    firstName: '',
                    lastName: '',
                    email: '',
                    password: '',
                    confirmPassword: '',
                    role: 'student'
                });
                setCurrentForm('login');
                setRegisterMessage('');
            }, 2000);

        } catch (error) {
            console.error('Registration error:', error);
            setRegisterError(error.message || t('login.register.registrationFailed'));
        } finally {
            setRegisterLoading(false);
        }
    };

    // Forgot password handler
    const handleForgotPassword = async (e) => {
        e.preventDefault();
        setForgotError('');
        setForgotMessage('');
        setForgotLoading(true);

        try {
            const response = await fetch(`${API_BASE_URL}/api/auth/forgot-password`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ email: forgotEmail })
            });

            const data = await response.json();

            if (!response.ok) {
                throw new Error(data.message || t('login.forgot.sendFailed'));
            }

            setForgotMessage(t('login.forgot.successMessage'));
            
            // Navigate to OTP verification page
            setTimeout(() => {
                history.push('/verify-otp', { email: forgotEmail });
                onClose();
            }, 1500);

        } catch (error) {
            console.error('Forgot password error:', error);
            setForgotError(error.message || t('login.forgot.sendFailed'));
        } finally {
            setForgotLoading(false);
        }
    };

    // Registration input handler
    const handleRegisterInputChange = (field, value) => {
        setRegisterData(prev => ({
            ...prev,
            [field]: value
        }));
    };

    // Form switching handlers
    const switchToRegister = () => {
        setCurrentForm('register');
        clearAllErrors();
    };

    const switchToLogin = () => {
        setCurrentForm('login');
        clearAllErrors();
    };

    const switchToForgot = () => {
        setCurrentForm('forgot');
        clearAllErrors();
    };

    // Clear all form errors and messages
    const clearAllErrors = () => {
        setFormError('');
        setRegisterError('');
        setRegisterMessage('');
        setForgotError('');
        setForgotMessage('');
    };

    // Clear forms when modal closes
    useEffect(() => {
        if (!isOpen) {
            setEmail('');
            setPassword('');
            setFormError('');
            setCurrentForm('login');
            setRegisterData({
                firstName: '',
                lastName: '',
                email: '',
                password: '',
                confirmPassword: '',
                role: 'student'
            });
            setForgotEmail('');
            clearAllErrors();
        }
    }, [isOpen]);

    // Render login form
    const renderLoginForm = () => (
        <>
            <div className="login-header">
                <div className="login-logo">
                    <div className="ring-container">
                        <div className="ring"></div>
                        <div className="ring"></div>
                        <div className="ring"></div>
                        <div className="ring"></div>
                        <div className="logo-text">FORUM ACADEMY</div>
                    </div>
                </div>
                <h2>{t('login.header.title')}</h2>
                <p>{t('login.header.subtitle')}</p>
            </div>
            
            {formError && (
                <div className="form-error modern">
                    <span className="material-icons">error_outline</span>
                    <span>{formError}</span>
                </div>
            )}
            
            <form className="login-form" onSubmit={handleLogin}>
                <div className="form-group">
                    <div className="input-wrapper">
                        <span className="material-icons input-icon">email</span>
                        <input
                            type="email"
                            id="login-modal-email"
                            placeholder={t('login.form.emailPlaceholder')}
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                            className="form-input modern"
                        />
                    </div>
                </div>
                
                <div className="form-group">
                    <div className="input-wrapper">
                        <span className="material-icons input-icon">lock</span>
                        <input
                            type={showPassword ? "text" : "password"}
                            id="login-modal-password"
                            placeholder={t('login.form.passwordPlaceholder')}
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                            className="form-input modern"
                        />
                        <button
                            type="button"
                            className="toggle-password"
                            onClick={() => setShowPassword(!showPassword)}
                            tabIndex="-1"
                            aria-label={showPassword ? t('login.form.hidePassword') : t('login.form.showPassword')}
                        >
                            <span className="material-icons">
                                {showPassword ? 'visibility_off' : 'visibility'}
                            </span>
                        </button>
                    </div>
                </div>
                
                <div className="form-options modern">
                    <label className="custom-checkbox modern">
                        <input
                            type="checkbox"
                            checked={rememberMe}
                            onChange={() => setRememberMe(!rememberMe)}
                        />
                        <span className="checkbox-mark"></span>
                        <span className="checkbox-label">{t('login.form.rememberMe')}</span>
                    </label>
                    <button
                        type="button"
                        className="forgot-link"
                        onClick={switchToForgot}
                    >
                        {t('login.form.forgotPassword')}
                    </button>
                </div>
                
                <button 
                    type="submit" 
                    className={`login-button modern ${isLoading ? 'loading' : ''}`}
                    disabled={isLoading}
                >
                    {isLoading ? (
                        <>
                            <span className="button-loader"></span>
                            <span>{t('login.form.signingIn')}</span>
                        </>
                    ) : (
                        <>
                            <span>{t('login.form.signIn')}</span>
                            <span className="material-icons button-icon">arrow_forward</span>
                        </>
                    )}
                </button>
                
                {/* Register section */}
                <div className="register-section">
                    <div className="divider">
                        <span>{t('login.register.newToPlatform')}</span>
                    </div>
                    <button
                        type="button"
                        className="register-button"
                        onClick={switchToRegister}
                    >
                        <span className="material-icons">person_add</span>
                        <span>{t('login.register.createAccount')}</span>
                    </button>
                </div>
            </form>
        </>
    );

    // Render registration form
    const renderRegisterForm = () => (
        <>
            <div className="login-header">
                <div className="login-logo">
                    <div className="ring-container">
                        <div className="ring"></div>
                        <div className="ring"></div>
                        <div className="ring"></div>
                        <div className="ring"></div>
                        <div className="logo-text">FORUM ACADEMY</div>
                    </div>
                </div>
                <h2>{t('login.register.title')}</h2>
                <p>{t('login.register.subtitle')}</p>
            </div>

            {registerError && (
                <div className="form-error modern">
                    <span className="material-icons">error_outline</span>
                    <span>{registerError}</span>
                </div>
            )}

            {registerMessage && (
                <div className="form-success modern">
                    <span className="material-icons">check_circle</span>
                    <span>{registerMessage}</span>
                </div>
            )}

            <form className="login-form" onSubmit={handleRegister}>
                {/* First Name */}
                <div className="form-group">
                    <div className="input-wrapper">
                        <span className="material-icons input-icon">person</span>
                        <input
                            type="text"
                            placeholder={t('login.register.firstNamePlaceholder')}
                            value={registerData.firstName}
                            onChange={(e) => handleRegisterInputChange('firstName', e.target.value)}
                            required
                            className="form-input modern"
                        />
                    </div>
                </div>

                {/* Last Name */}
                <div className="form-group">
                    <div className="input-wrapper">
                        <span className="material-icons input-icon">person_outline</span>
                        <input
                            type="text"
                            placeholder={t('login.register.lastNamePlaceholder')}
                            value={registerData.lastName}
                            onChange={(e) => handleRegisterInputChange('lastName', e.target.value)}
                            required
                            className="form-input modern"
                        />
                    </div>
                </div>

                {/* Email */}
                <div className="form-group">
                    <div className="input-wrapper">
                        <span className="material-icons input-icon">email</span>
                        <input
                            type="email"
                            placeholder={t('login.register.emailPlaceholder')}
                            value={registerData.email}
                            onChange={(e) => handleRegisterInputChange('email', e.target.value)}
                            required
                            className="form-input modern"
                        />
                    </div>
                </div>

                {/* Role Selection */}
                <div className="form-group">
                    <div className="input-wrapper">
                        <span className="material-icons input-icon">school</span>
                        <select
                            value={registerData.role}
                            onChange={(e) => handleRegisterInputChange('role', e.target.value)}
                            className="form-input modern"
                            required
                        >
                            <option value="student">{t('login.register.studentRole')}</option>
                            <option value="teacher">{t('login.register.teacherRole')}</option>
                        </select>
                    </div>
                </div>

                {/* Password */}
                <div className="form-group">
                    <div className="input-wrapper">
                        <span className="material-icons input-icon">lock</span>
                        <input
                            type={showRegisterPassword ? "text" : "password"}
                            placeholder={t('login.register.passwordPlaceholder')}
                            value={registerData.password}
                            onChange={(e) => handleRegisterInputChange('password', e.target.value)}
                            required
                            className="form-input modern"
                            minLength={6}
                        />
                        <button
                            type="button"
                            className="toggle-password"
                            onClick={() => setShowRegisterPassword(!showRegisterPassword)}
                            tabIndex="-1"
                            aria-label={showRegisterPassword ? t('login.form.hidePassword') : t('login.form.showPassword')}
                        >
                            <span className="material-icons">
                                {showRegisterPassword ? 'visibility_off' : 'visibility'}
                            </span>
                        </button>
                    </div>
                </div>

                {/* Confirm Password */}
                <div className="form-group">
                    <div className="input-wrapper">
                        <span className="material-icons input-icon">lock_outline</span>
                        <input
                            type={showConfirmPassword ? "text" : "password"}
                            placeholder={t('login.register.confirmPasswordPlaceholder')}
                            value={registerData.confirmPassword}
                            onChange={(e) => handleRegisterInputChange('confirmPassword', e.target.value)}
                            required
                            className="form-input modern"
                            minLength={6}
                        />
                        <button
                            type="button"
                            className="toggle-password"
                            onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                            tabIndex="-1"
                            aria-label={showConfirmPassword ? t('login.form.hidePassword') : t('login.form.showPassword')}
                        >
                            <span className="material-icons">
                                {showConfirmPassword ? 'visibility_off' : 'visibility'}
                            </span>
                        </button>
                    </div>
                </div>

                <button 
                    type="submit" 
                    className={`login-button modern ${registerLoading ? 'loading' : ''}`}
                    disabled={registerLoading}
                >
                    {registerLoading ? (
                        <>
                            <span className="button-loader"></span>
                            <span>{t('login.register.creating')}</span>
                        </>
                    ) : (
                        <>
                            <span>{t('login.register.createAccount')}</span>
                            <span className="material-icons button-icon">person_add</span>
                        </>
                    )}
                </button>

                <button
                    type="button"
                    className="back-to-login"
                    onClick={switchToLogin}
                >
                    <span className="material-icons">arrow_back</span>
                    {t('login.register.backToLogin')}
                </button>
            </form>
        </>
    );

    // Render forgot password form
    const renderForgotForm = () => (
        <>
            <div className="login-header">
                <div className="login-logo">
                    <div className="ring-container">
                        <div className="ring"></div>
                        <div className="ring"></div>
                        <div className="ring"></div>
                        <div className="ring"></div>
                        <div className="logo-text">FORUM ACADEMY</div>
                    </div>
                </div>
                <h2>{t('login.forgot.title')}</h2>
                <p>{t('login.forgot.subtitle')}</p>
            </div>

            {forgotError && (
                <div className="form-error modern">
                    <span className="material-icons">error_outline</span>
                    <span>{forgotError}</span>
                </div>
            )}

            {forgotMessage && (
                <div className="form-success modern">
                    <span className="material-icons">check_circle</span>
                    <span>{forgotMessage}</span>
                </div>
            )}

            <form className="login-form" onSubmit={handleForgotPassword}>
                <div className="form-group">
                    <div className="input-wrapper">
                        <span className="material-icons input-icon">email</span>
                        <input
                            type="email"
                            placeholder={t('login.forgot.emailPlaceholder')}
                            value={forgotEmail}
                            onChange={(e) => setForgotEmail(e.target.value)}
                            required
                            className="form-input modern"
                        />
                    </div>
                </div>

                <button 
                    type="submit" 
                    className={`login-button modern ${forgotLoading ? 'loading' : ''}`}
                    disabled={forgotLoading}
                >
                    {forgotLoading ? (
                        <>
                            <span className="button-loader"></span>
                            <span>{t('login.forgot.sending')}</span>
                        </>
                    ) : (
                        <>
                            <span>{t('login.forgot.sendButton')}</span>
                            <span className="material-icons button-icon">send</span>
                        </>
                    )}
                </button>

                <button
                    type="button"
                    className="back-to-login"
                    onClick={switchToLogin}
                >
                    <span className="material-icons">arrow_back</span>
                    {t('login.forgot.backToLogin')}
                </button>
            </form>
        </>
    );

    return (
        <div className={`login-modal-overlay ${isOpen ? 'active' : ''} ${isVisible ? 'visible' : ''}`} onClick={onClose}>
            <div className="login-modal" onClick={e => e.stopPropagation()}>
                <div className="modal-glass-effect"></div>
                
                <button className="modal-close-btn" onClick={onClose} aria-label={t('login.closeModal')}>
                    <span className="material-icons">close</span>
                </button>
                
                <div className="login-modal-content">
                    <div className="login-form-container">
                        {currentForm === 'login' && renderLoginForm()}
                        {currentForm === 'register' && renderRegisterForm()}
                        {currentForm === 'forgot' && renderForgotForm()}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default LoginModal;
